/c local o={entities={},recipes={},modules={},technologies={}} local BELT={["transport-belt"]=true,["underground-belt"]=true,["splitter"]=true,["loader"]=true,["loader-1x1"]=true} local UG={["underground-belt"]=true,["pipe-to-ground"]=true,["loader"]=true,["loader-1x1"]=true} local CM={["assembling-machine"]=true,["furnace"]=true,["rocket-silo"]=true} local PUMP={["pump"]=true,["offshore-pump"]=true} local ALL={["transport-belt"]=true,["underground-belt"]=true,["splitter"]=true,["loader"]=true,["loader-1x1"]=true,["inserter"]=true,["pipe"]=true,["pipe-to-ground"]=true,["pump"]=true,["assembling-machine"]=true,["furnace"]=true,["rocket-silo"]=true,["lab"]=true,["mining-drill"]=true,["offshore-pump"]=true,["electric-pole"]=true,["solar-panel"]=true,["accumulator"]=true,["boiler"]=true,["generator"]=true,["reactor"]=true,["heat-pipe"]=true,["fusion-reactor"]=true,["fusion-generator"]=true,["burner-generator"]=true,["beacon"]=true,["roboport"]=true,["container"]=true,["logistic-container"]=true,["linked-container"]=true,["radar"]=true,["lamp"]=true,["arithmetic-combinator"]=true,["decider-combinator"]=true,["constant-combinator"]=true,["programmable-speaker"]=true,["selector-combinator"]=true,["wall"]=true,["gate"]=true,["ammo-turret"]=true,["electric-turret"]=true,["fluid-turret"]=true,["straight-rail"]=true,["curved-rail"]=true,["train-stop"]=true,["half-diagonal-rail"]=true,["curved-rail-a"]=true,["curved-rail-b"]=true,["agricultural-tower"]=true,["asteroid-collector"]=true,["thruster"]=true,["space-platform-hub"]=true} local function K(tbl) if not tbl then return nil end local out={} for k,_ in pairs(tbl) do out[#out+1]=k end return out end local function S(fn) local ok,v=pcall(fn) if ok then return v end return nil end local function V2(v) if not v or type(v)~="table" then return nil end local x=v.x if x==nil then x=v[1] end local y=v.y if y==nil then y=v[2] end if type(x)~="number" or type(y)~="number" then return nil end return {x=x,y=y} end local function DR(e) local es=S(function() return e.electric_energy_source_prototype end) if not es then return nil end return S(function() return es.drain end) end local function FB(e) local fbs=S(function() return e.fluidbox_prototypes end) if not fbs or #fbs==0 then return nil end local out={} for i,fb in ipairs(fbs) do local conns={} local pc=S(function() return fb.pipe_connections end) if pc then for _,c in ipairs(pc) do local ps={} if c.positions then for _,p in ipairs(c.positions) do local v=V2(p) if v then ps[#ps+1]=v end end end conns[#conns+1]={positions=ps,flow_direction=c.flow_direction,connection_type=c.connection_type,max_underground_distance=c.max_underground_distance} end end out[#out+1]={index=i,production_type=S(function() return fb.production_type end),volume=S(function() return fb.volume end),filter=S(function() return fb.filter and fb.filter.name end),connections=conns} end return out end for name,e in pairs(prototypes.entity) do if ALL[e.type] and not e.hidden then local t=e.type local ent={name=name,type=t,tile_width=e.tile_width,tile_height=e.tile_height} local cb=e.collision_box if cb then local lt=V2(cb.left_top) local rb=V2(cb.right_bottom) if lt and rb then ent.collision_box={lt=lt,rb=rb} end end ent.energy_drain=DR(e) local itp=S(function() return e.items_to_place_this end) if itp and #itp>0 then local items={} for _,it in ipairs(itp) do if it and it.name then items[#items+1]=it.name end end if #items>0 then ent.items_to_place_this=items end end local sc=S(function() return e.surface_conditions end) if sc and #sc>0 then local sco={} for _,c in ipairs(sc) do sco[#sco+1]={property=c.property,min=c.min,max=c.max} end ent.surface_conditions=sco end if CM[t] then ent.crafting_categories=K(e.crafting_categories) ent.crafting_speed=S(function() return e.get_crafting_speed() end) ent.module_slots=e.module_inventory_size ent.energy_usage=e.energy_usage ent.allowed_effects=K(e.allowed_effects) ent.allowed_module_categories=K(S(function() return e.allowed_module_categories end)) ent.fluid_boxes=FB(e) end if t=="lab" then local inp={} if e.lab_inputs then for _,v in pairs(e.lab_inputs) do inp[#inp+1]=(type(v)=="table" and v.name) or v end end ent.lab_inputs=inp ent.researching_speed=S(function() return e.get_researching_speed() end) ent.module_slots=e.module_inventory_size ent.energy_usage=e.energy_usage ent.allowed_effects=K(e.allowed_effects) ent.allowed_module_categories=K(S(function() return e.allowed_module_categories end)) end if t=="mining-drill" then ent.resource_categories=K(e.resource_categories) ent.mining_speed=e.mining_speed ent.module_slots=e.module_inventory_size ent.energy_usage=e.energy_usage ent.allowed_effects=K(e.allowed_effects) ent.allowed_module_categories=K(S(function() return e.allowed_module_categories end)) ent.fluid_boxes=FB(e) ent.vector_to_place_result=V2(S(function() return e.vector_to_place_result end)) ent.resource_searching_radius=S(function() return e.mining_drill_radius end) end if BELT[t] then ent.belt_speed=e.belt_speed end if UG[t] then ent.max_underground_distance=e.max_underground_distance end if t=="inserter" then ent.inserter_pickup_position=V2(S(function() return e.inserter_pickup_position end)) ent.inserter_drop_position=V2(S(function() return e.inserter_drop_position end)) ent.inserter_extension_speed=S(function() return e.get_inserter_extension_speed() end) ent.inserter_rotation_speed=S(function() return e.get_inserter_rotation_speed() end) end if PUMP[t] then ent.pumping_speed=S(function() return e.pumping_speed end) ent.energy_usage=e.energy_usage ent.fluid_boxes=FB(e) end if t=="pipe" or t=="pipe-to-ground" then ent.fluid_boxes=FB(e) end if t=="electric-pole" then ent.supply_area_distance=S(function() return e.get_supply_area_distance() end) ent.max_wire_distance=S(function() return e.get_max_wire_distance() end) end if t=="generator" or t=="fusion-generator" or t=="burner-generator" then ent.max_power_output=S(function() return e.max_power_output end) ent.fluid_usage_per_tick=S(function() return e.fluid_usage_per_tick end) ent.fluid_boxes=FB(e) end if t=="solar-panel" then ent.max_power_output=S(function() return e.max_power_output end) end if t=="boiler" or t=="fusion-reactor" then ent.target_temperature=S(function() return e.target_temperature end) ent.energy_usage=e.energy_usage ent.fluid_boxes=FB(e) end if t=="offshore-pump" then ent.fluid_boxes=FB(e) end if t=="beacon" then ent.distribution_effectivity=e.distribution_effectivity ent.supply_area_distance=S(function() return e.get_supply_area_distance() end) ent.module_slots=e.module_inventory_size ent.allowed_effects=K(e.allowed_effects) ent.allowed_module_categories=K(S(function() return e.allowed_module_categories end)) ent.energy_usage=e.energy_usage end if t=="roboport" then ent.logistic_radius=e.logistic_radius ent.construction_radius=e.construction_radius end if t=="container" or t=="logistic-container" or t=="linked-container" then local inv=S(function() return e.get_inventory_size(defines.inventory.chest) end) if inv and inv>0 then ent.inventory_size=inv end end o.entities[#o.entities+1]=ent end end for n,r in pairs(prototypes.recipe) do local i={} for _,v in pairs(r.ingredients) do i[#i+1]={type=v.type,name=v.name,amount=v.amount} end local p={} for _,v in pairs(r.products) do p[#p+1]={type=v.type,name=v.name,amount=v.amount,probability=v.probability} end local rsc=S(function() return r.surface_conditions end) local rsco=nil if rsc and #rsc>0 then rsco={} for _,c in ipairs(rsc) do rsco[#rsco+1]={property=c.property,min=c.min,max=c.max} end end o.recipes[#o.recipes+1]={name=n,category=r.category,energy=r.energy,enabled=r.enabled,ingredients=i,products=p,allowed_module_categories=K(S(function() return r.allowed_module_categories end)),surface_conditions=rsco} end for n,it in pairs(prototypes.item) do local ef=S(function() return it.module_effects end) if ef then local eo={} for _,k in ipairs({"speed","productivity","consumption","pollution","quality"}) do if ef[k]~=nil then eo[k]=ef[k] end end o.modules[#o.modules+1]={name=n,category=S(function() return it.category end),tier=S(function() return it.tier end),effects=eo} end end for n,tc in pairs(prototypes.technology) do local ur={} local efs=S(function() return tc.effects end) if efs then for _,ef in ipairs(efs) do if ef.type=="unlock-recipe" and ef.recipe then ur[#ur+1]=ef.recipe end end end local pq={} local pr=S(function() return tc.prerequisites end) if pr then for k,_ in pairs(pr) do pq[#pq+1]=k end end o.technologies[#o.technologies+1]={name=n,prerequisites=pq,unlock_recipes=ur,enabled=S(function() return tc.enabled end),essential=S(function() return tc.essential end),visible_when_disabled=S(function() return tc.visible_when_disabled end),upgrade=S(function() return tc.upgrade end),max_level=S(function() return tc.max_level end)} end helpers.write_file("factorio-data.json",helpers.table_to_json(o)) game.print("Exported "..#o.entities.." entities, "..#o.recipes.." recipes, "..#o.modules.." modules, "..#o.technologies.." technologies")
